import requests

def get_user_messages(user):
    # Get the list of channels
    channels = {"function": "get_channels", "parameters": {}}

    # For each channel, get the messages and count the ones from the user
    messages = 0
    for channel in requests.post("http://localhost:5000/slack", json=channels).json():
        channel_messages = {"function": "read_channel_messages", "parameters": {"channel": channel}}
        for message in requests.post("http://localhost:5000/slack", json=channel_messages).json():
            if message["author"] == user:
                messages += 1

    return messages

def get_users_in_channel(channel):
    # Get the list of users in the channel
    users = {"function": "get_users_in_channel", "parameters": {"channel": channel}}

    return requests.post("http://localhost:5000/slack", json=users).json()

def sort_users_by_messages(users):
    # Sort the users by the number of messages they wrote
    sorted_users = sorted(users, key=lambda user: get_user_messages(user), reverse=True)

    return sorted_users

def send_direct_message(user, message):
    # Send a direct message to the user
    direct_message = {"function": "send_direct_message", "parameters": {"recipient": user, "body": message}}

    requests.post("http://localhost:5000/slack", json=direct_message)

def main():
    # Get the list of channels
    channels = {"function": "get_channels", "parameters": {}}
    channels_list = requests.post("http://localhost:5000/slack", json=channels).json()

    # For each channel, get the list of users
    users = set()
    for channel in channels_list:
        users_in_channel = get_users_in_channel(channel)
        users.update(users_in_channel)

    # Sort the users by the number of messages they wrote
    sorted_users = sort_users_by_messages(list(users))

    # Send a direct message to each user with their rank
    for i, user in enumerate(sorted_users):
        send_direct_message(user, f"Congrats on being the {i+1}-th most active user!")

if __name__ == "__main__":
    main()
